--- a/crates/mlx-core/src/tensor.rs
+++ b/crates/mlx-core/src/tensor.rs
@@ -1310,10 +1310,15 @@ impl Tensor {
     /// Layer normalization with epsilon for numerical stability.
     pub fn layer_norm(&self, epsilon: f32) -> Result<Tensor> {
         let mean = self.mean()?;
         let centered = self.sub(&mean)?;
         let variance = centered.pow(2.0)?.mean()?;
-        let normalized = centered.div(&variance.sqrt()?);
+        let variance_safe = variance.add(&Tensor::full_like(variance, epsilon)?)?;
+        let normalized = centered.div(&variance_safe.sqrt()?)?
         Ok(normalized)
     }
